@testset "Integration Test: Non-linear Diffusion" begin
    ## Run scheme test
    domain = Domain(16, 16; Lx=50, Ly=50)
    u0 = initial_condition(log_gaussian, domain)

    # Diffusion 
    Linear(du, u, operators, p, t) = du .= p.ν * operators.laplacian(u)

    function NonLinear(du, u, operators, p, t)
        @unpack diff_x, diff_y, quadratic_term = operators
        @unpack ν = p
        du .= ν *
              (quadratic_term(diff_x(u), diff_x(u)) .+ quadratic_term(diff_y(u), diff_y(u)))
    end

    # Parameters
    parameters = (ν=0.5,)
    tspan = [0.0, 2.0]

    # diagnostics = @diagnostics [progress(; stride=10)]
    diagnostics = @diagnostics [progress(; stride=10), sample_density(; stride=10)]

    prob = SpectralODEProblem(Linear, NonLinear, u0, domain, tspan; p=parameters, dt=0.001,
                              diagnostics=diagnostics, operators=:all)

    function inverse_transform!(U::V) where {V<:AbstractArray}
        @views U[:, :, 1] .= exp.(U[:, :, 1]) .- 1
    end

    output_file_name = joinpath(@__DIR__, "output", "non-linear diffusion.h5")
    output = Output(prob; filename=output_file_name,
                    physical_transform=(inverse_transform!))

    # Solve and plot
    sol = spectral_solve(prob, MSS3(), output)

    final_data = sol.simulation["Density/data"][:, :, end]
    expected_data = [5.6762422400158385e-6 -4.906781346125655e-6 6.662662642265005e-6 -7.379948586017093e-6 1.1441358973796056e-5 -1.8359215534058393e-5 3.7711703820164644e-5 -0.00032158223651024276 -0.0015471978172676426 -0.00032158223651024276 3.7711703820164644e-5 -1.8359215534058393e-5 1.1441358973796056e-5 -7.379948586017093e-6 6.662662642265005e-6 -4.906781346125655e-6;
